module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [15:0] a, b;
reg [31:0] p;
reg [4:0] i;
reg done_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a <= 0;
        b <= 0;
        p <= 0;
        i <= 0;
        done_r <= 0;
    end
    else if (start) begin
        if (i == 0) begin
            a <= ain;
            b <= bin;
        end
        else if (i < 16) begin
            if (b[0]) begin
                p <= p + (a << (i - 1));
            end
            b <= b >> 1;
            i <= i + 1;
        end
        else begin
            done_r <= 1;
        end
    end
    else begin
        p <= 0;
        i <= 0;
        done_r <= 0;
    end
end

assign yout = p;
assign done = done_r;

endmodule
